event_grid_client = EventGridPublisherClient(endpoint=os.environ["EVENT_GRID_ENDPOINT"], credential=credential)

# Define Cosmos DB container
database_name = os.environ["COSMOS_DB_DATABASE"]
container_name = os.environ["COSMOS_DB_CONTAINER"]
container = cosmos_client.get_database_client(database_name).get_container_client(container_name)

def main(blob: func.InputStream):
    logging.info(f"Processing blob: {blob.name}, Size: {blob.length} bytes")

    # Read file content
    file_content = blob.read().decode('utf-8')
    results = process_file(file_content)

    # Write results to Cosmos DB
    container.upsert_item(results)

    # Send notification via Event Grid
    event = EventGridEvent(
        event_type="FileProcessed",
        data=results,
        subject=f"Blob/{blob.name}",
        event_time=func.datetime.datetime.utcnow(),
        id=blob.name
    )
    event_grid_client.send(event)

